window.__QUIZ_DATA__=[{"id":"theory>Biology>2000>PART I>1>a","subject":"Biology","year":"2000","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"What is a sense organ?","images":[],"marking_scheme":"A group of specialised cells, tissues, or receptors which is able to recieve, collect, perceive or detect stimulus and transmit the information, impulse or message to the central nervous system.","marks":"3","difficulty":"1"},{"id":"theory>Biology>2000>PART I>1>b>i","subject":"Biology","year":"2000","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"State two main function of the ear","images":[],"marking_scheme":"For hearing  For maintainance of balance","marks":"3","difficulty":"2"},{"id":"theory>Biology>2000>PART I>1>b>ii","subject":"Biology","year":"2000","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"Explain the mechanism involved in one of the function stated in (b)(i) above","images":[],"marking_scheme":"I.For hearing (mechanism involved in hearing)  - The pinnae collects sounds waves in the ear, concentrates them and passes them on through the external auditory canal/meatus.  - The waves causes the tympanic membrane (eardrum) to vibrate   - The vibration are passed on to the ear ossicles (malleusincus and stapes)  - The oddicles amplify them   - The round oval window also vibrates passing the waves into the cavity of the inner ear/cochlea.  -In the inner ear/cochlea the perilymph vibrates and transmits the waves in the cochlea, causing the endolymph of the cochlea to vibrates  - The vibration are transmitted across the organ of corti, or sensry nerve cell or basile membrane  - Impluses are set up which stimuates the aduitory nerve cell, which then transmits the impulse to the brain   OR  II. Mechanism of maintenance of balance  -It all begines in the head, head movement in any direction affects the fluid or endolymph in the corresponding semicircular canal which are at right angle to each other   - This forces the sensory cells or gelationus cpular in the ampulla to set up impulses through the auditory nerve to the brain and interm for interpretation  - The brain relay impulses tot he determing the position of the body","marks":"3","difficulty":"3"},{"id":"theory>Biology>2000>PART I>1>c","subject":"Biology","year":"2000","type":"Theory","sub_label":"c","group":"","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"With the aid of a large labelled diagram illustrated the eye defect of short-sighted, and its correction","images":["data:image/png;base64,"],"marking_scheme":"Image formed before eyeball and eyeball is too long     Correction with concave len diverge the light and causes image to form on the retina","marks":"4","difficulty":"3"},{"id":"theory>Biology>2000>PART I>2>a","subject":"Biology","year":"2000","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State five different method used in vegetative propagation in plants giving an example in each case","images":[],"marking_scheme":"1. Use of modified underground stem e.g cocoa, yam, corn,sucker e.t.c  2. cutting of the stem with two or three modes and buds e.g cassava, cotton, hibiscus e.t.c  3. Flsehy leaves e.g onion, bryophyllum/bubils  4. Grafting or parts of one plant is joined to another of the same or related species E.g citrus, mango . e.t.c  5. Budding a dormant bud from one plant e.g citrus , mango e.t.c  6. Layering: a branch close to the soil is bent so that part of the branch touches the soil.   - tie the end of te branch to a firm support, remove ring or bank from the part of the branch touching the soil or make slit halfway through the branch  -push tis part below the soil and place heavy object on heap E.g bougainvillea, rose plant e.t.c","marks":"5","difficulty":"2"},{"id":"theory>Biology>2000>PART I>2>b>i","subject":"Biology","year":"2000","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"state five    advantages of vegetative propagation","images":[],"marking_scheme":"1. Only one parent is required  2. Offspring mature rapidly  3. They are less susceptible to adverse weather conditions  4. It is easily established  5. Desirable charateristics are retained","marks":"3","difficulty":"1"},{"id":"theory>Biology>2000>PART I>2>b>ii","subject":"Biology","year":"2000","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"state five  disadvantage of vegetative propagation","images":[],"marking_scheme":"1. No new varieties are produced   2. Reduced resistance to change in climate or reduced adaptation to environment.  3. Overcrowding of given area of land  4. Colonisation is unlikely since offspring are always produced close to parent  5. Undesirable charateristics can be easily passed to offspring","marks":"3","difficulty":"1"},{"id":"theory>Biology>2000>PART I>3>a","subject":"Biology","year":"2000","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"list five classes of food other than carbonhydrate","images":[],"marking_scheme":"1. proteins  2. fat and oils  3. vitamins   4. mineral salts   5. water","marks":"3","difficulty":"1"},{"id":"theory>Biology>2000>PART I>3>b","subject":"Biology","year":"2000","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Explain why glucose is taken by an athlete ready for a race rather than corn meal","images":[],"marking_scheme":"Why glucose is taken by an athlete ready for race and not corn meal. Glucose is the simplest form of carbonhydrate which does not require any form of digestion. Hence it is absorbed in the ileum(small intestine) where it diffuses into the blood stream, it is then oxidized and utilized within the shortest time possible  corn meal is a complex carbohydrates(starch) and will require series of hydrolysis in its digestive process which starts in the mouth, then duodenum and then the ileum, and it will take longer time to give energy.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2000>PART I>3>c","subject":"Biology","year":"2000","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Describe the test for starch","images":[],"marking_scheme":"- obtain any starchy food e.g yam, cassava, potato e.t.c.  -Crush the starch and add water to create a starch solution  -put a few drops of starch on a white tile  - Add one or two drops of iodine, the solution will turn blue-black indicating the presence of starch","marks":"3","difficulty":"2"},{"id":"theory>Biology>2000>PART I>4>a>i","subject":"Biology","year":"2000","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"Name the four levels or organisation in living oganism","images":[],"marking_scheme":"4 levels of organisation   1. cell  2. tissue   3. organ  4. system","marks":"3","difficulty":"1"},{"id":"theory>Biology>2000>PART I>4>a>ii","subject":"Biology","year":"2000","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"Explain two of the levels of organisation named in (a)(i) above","images":[],"marking_scheme":"1. cell : is the basic structure and functional unit of life   - it is bound by a membrane containig nucleus and cytoplasm  - some cells can exist independently exhibiting all the charateristics of living things  - They have inclusions referred to as organelles  2. TISSUE: it is a collection of similar cells performing the same function  -some tissue cannot exist on their own, while others can exist independently e.g Hydra  They have the same origin and occupy the same position in the body of the organism  3. ORGAN : is a collection of different tissue that perform common functions  -organ carry out a single function e.g heart  -some organs perform multiple functions e.g kidney  4. SYSTEM : is made of different oragans   -They perfom specific functions  - They are peculiar to higher organism e.g nervous system","marks":"3","difficulty":"2"},{"id":"theory>Biology>2000>PART I>4>a>iii","subject":"Biology","year":"2000","type":"Theory","sub_label":"iii","group":"","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"State the level of organisation of Euglena, onion bulb and blood","images":[],"marking_scheme":"Level of organisation of the following:  Euglena - cell  onion bulb- organ  Blood  - tissue","marks":"2","difficulty":"2"},{"id":"theory>Biology>2000>PART I>4>b","subject":"Biology","year":"2000","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"Give four advantages of complexity of organisation in higher organism","images":[],"marking_scheme":"1. It leads to cellular differentiation: cells are differentiated to form tissue that perform similar functions  2. it leads to internal structural specialisation   3. Mutual interdependence between component cells in other words division of labour.  4. it leads to efficiency  5. It increases adaptation to environment","marks":"2","difficulty":"2"},{"id":"theory>Biology>2000>PART I>4>c>i","subject":"Biology","year":"2000","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"State one advantage Amoeba has over cell of lizard, in relation to their level of organisation","images":[],"marking_scheme":"There is individality of life in ameoba i.e each cell of amoeba can exist as an individual and perfom life processes but individual cell of the lizard cannot survive as a unit.  Amoeba's simple level of organization has two key advantages over a cell from a lizard:  - Greater flexibility and adaptability to changing environments  - Individuality, allowing each Amoeba to be a self-contained, independent organism with its own complete set of organs and systems.    These advantages enable Amoeba to thrive in its environment in ways that a cell from a more complex organism like a lizard cannot.","marks":"1","difficulty":"2"},{"id":"theory>Biology>2000>PART I>4>c>ii","subject":"Biology","year":"2000","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"Give two reasons for the advantage","images":[],"marking_scheme":"1. surface area is large, therefore diffusion is efficient   2. Distance which material travel in cell is short  3. Ameoba is in direct contact with the external environment.  OR  1. Greater flexibility and adaptability:      - Simple structure: Amoeba's simple structure allows it to change shape and move easily, making it more flexible and adaptable to its environment.  2. Efficient diffusion:      - Large surface area: Amoeba's large surface area relative to its volume allows for efficient diffusion of nutrients and waste, making it more self-sufficient.  3. Individuality:      - Direct contact with the external environment: Amoeba's direct contact with its environment means it can respond directly to stimuli and obtain resources without relying on other cells or systems.","marks":"1","difficulty":"1"},{"id":"theory>Biology>2000>PART II>5>a","subject":"Biology","year":"2000","type":"Theory","sub_label":"a","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : NUTRIENT CYCLING IN NATURE","question":"Describe the water cycle using annoted diagram(s) only","images":["data:image/jpeg;base64,"],"marking_scheme":"The water cycle is the continous movement of water from the atmosphere to the earth, and from the earth to the atmosphere,","marks":"10","difficulty":"3"},{"id":"theory>Biology>2000>PART II>5>b","subject":"Biology","year":"2000","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"What is the importance of water to living organisms?","images":[],"marking_scheme":"1.Water provides the medium for absorption of dissolved mineral salts by plants  2.Water is essential in photosynthesis  3.Water aids excretion of wase products in plants and animals.  4.It consitute a large portion of blood  5. Water regulates body temperature","marks":"5","difficulty":"1"},{"id":"theory>Biology>2000>PART II>6>a","subject":"Biology","year":"2000","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"Explain the term osmosis","images":[],"marking_scheme":"OSMOSIS: is the process by which water molecules or solvent move from a region of weaker concerntration to a region of stronger solution through a semi-permeable membrane  OR  Movement of water or water molecules from a region of higher concentration of water to a region of lower concentration of water molecules through a semi-permeable membrane","marks":"5","difficulty":"2"},{"id":"theory>Biology>2000>PART II>6>b","subject":"Biology","year":"2000","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Describe an experiment to show that the xylem tissue conducts water from root to shoot","images":[],"marking_scheme":"- A young herbaceous plant is uprooted   - The root are washed with water to remove soil particles    - A solution of dye, eosin or red ink is made in a beaker  - The root system is immersed into the solution and exposed to sunlight.  -The set-up is allowed to stand for 1-6hours after which the plant is removed and the root is washed thoroughly  - Observing the section the section under microscope, it is observed that only the xylem is stained by the dye.  - This indicates that water moves through xylem tissue.","marks":"5","difficulty":"3"},{"id":"theory>Biology>2000>PART II>6>c>i","subject":"Biology","year":"2000","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"Explain what happens to a red blood cell when placed in a hypotonic solution","images":[],"marking_scheme":"- Water enters cell via osmosis  - The red blood cell begins to swell  - The swelling takes place until the red blood cell burst i.e till haemolysis occurs","marks":"3","difficulty":"2"},{"id":"theory>Biology>2000>PART II>6>c>ii","subject":"Biology","year":"2000","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"Mention three conditions that may cause haemolysis","images":[],"marking_scheme":"-Disease condition   -poisoning  -Abuse of drugs  -Industrial activities/pollution  - Disease attack: Certain diseases, such as malaria, sickle cell anemia, and autoimmune disorders, can cause hemolysis.  - Abuse or use of drugs: Certain drugs, such as antibiotics and anti-cancer drugs, can cause hemolysis as a side effect.  - Poisoning: Exposure to certain toxins, such as lead and pesticides, can cause hemolysis.  - Industrial activities/pollution: Exposure to certain industrial chemicals and pollutants, such as benzene and heavy metals, can cause haemolysis.","marks":"3","difficulty":"1"}];